import { ethers } from 'ethers'
import TronWeb from 'tronweb'

import { getLogger, sleep } from '@layerzerolabs/lz-utilities'

import { Time } from './time'
import { StrategyFactory } from './url'

import type {
    BlockTransaction,
    ChainParameter,
    ContractExecutionParams,
    ContractInfo,
    Transaction,
    TransactionInfo,
    TransactionResult,
} from 'tronweb'

/**
 * Enum representing the types of transactions that can be performed on the Tron network.
 */
export enum TronTransactionType {
    TRIGGER_SMART_CONTRACT = 'TriggerSmartContract',
}

/**
 * Interface representing the overrides for a transaction.
 */
export interface TransactionOverrides {
    /**
     * The gas limit for the transaction.
     */
    gasLimit?: number

    /**
     * The gas price for the transaction.
     */
    gasPrice?: number

    /**
     * The energy factor for the transaction.
     */
    energyFactor?: number

    /**
     * The value to be sent with the transaction.
     */
    value?: number
}

/**
 * Interface representing a partial Tron transaction.
 */
export interface PartialTronTransaction {
    /**
     * Indicates whether the transaction is visible.
     */
    visible: boolean

    /**
     * The transaction ID.
     */
    txID: string

    /**
     * The raw data in hexadecimal format.
     */
    raw_data_hex: string

    /**
     * The raw data of the transaction.
     * @see {@link PartialTronTransactionContract}
     */
    raw_data: {
        contract: [PartialTronTransactionContract]
    }
}

/**
 * Interface representing a full Tron transaction.
 */
export interface TronTransaction extends PartialTronTransaction {
    /**
     * The raw data of the transaction.
     */
    raw_data: {
        /**
         * The contract details of the transaction.
         * @see {@link FullTronTransactionContract}
         */
        contract: [FullTronTransactionContract]

        /**
         * The reference block bytes.
         */
        ref_block_bytes: string

        /**
         * The reference block hash.
         */
        ref_block_hash: string

        /**
         * The expiration time of the transaction.
         */
        expiration: number

        /**
         * The fee limit for the transaction.
         */
        fee_limit: number

        /**
         * The timestamp of the transaction.
         */
        timestamp: number
    }
}

/**
 * Interface representing a signed Tron transaction.
 */
export interface SignedTronTransaction extends TronTransaction {
    /**
     * The signatures of the transaction.
     */
    signature: string[]
}

/**
 * Interface representing the parameter value of a partial Tron transaction.
 */
interface PartialTronTransactionParameterValue {
    /**
     * The data of the transaction.
     */
    data: string

    /**
     * The contract address.
     */
    contract_address: string

    /**
     * The owner address.
     */
    owner_address: string
}

/**
 * Interface representing the parameter value of a full Tron transaction.
 */
interface TronTransactionParameterValue extends PartialTronTransactionParameterValue {
    /**
     * The token ID.
     */
    token_id?: number

    /**
     * The call token value.
     */
    call_token_value?: number

    /**
     * The call value.
     */
    call_value?: number
}

/**
 * Interface representing the parameter of a Tron transaction.
 * @template T - The type of the parameter value.
 */
interface TronTransactionParameter<T> {
    /**
     * The value of the parameter.
     */
    value: T

    /**
     * The type URL of the parameter.
     */
    type_url: `type.googleapis.com/protocol.${TronTransactionType}`
}

/**
 * Interface representing a Tron transaction contract.
 * @template T - The type of the parameter value.
 */
interface TronTransactionContract<T> {
    /**
     * The parameter of the transaction contract.
     */
    parameter: TronTransactionParameter<T>

    /**
     * The type of the transaction contract.
     */
    type: TronTransactionType

    /**
     * The permission ID for the transaction contract.
     */
    Permission_id?: number
}

/**
 * Type representing a partial Tron transaction contract.
 */
type PartialTronTransactionContract = TronTransactionContract<PartialTronTransactionParameterValue>

/**
 * Type representing a full Tron transaction contract.
 */
type FullTronTransactionContract = TronTransactionContract<TronTransactionParameterValue>

/**
 * Interface representing the raw data of a Tron block header.
 */
interface TronBlockHeaderRawData {
    /**
     * The block number.
     */
    number: number

    /**
     * The transaction trie root.
     */
    txTrieRoot: string

    /**
     * The witness address.
     */
    witness_address: string

    /**
     * The parent hash.
     */
    parentHash: string

    /**
     * The timestamp of the block.
     */
    timestamp: number
}

/**
 * Interface representing a Tron block header.
 */
interface TronBlockHeader {
    /**
     * The raw data of the block header.
     */
    raw_data: TronBlockHeaderRawData

    /**
     * The witness signature.
     */
    witness_signature: string
}

/**
 * Interface representing Tron block data.
 */
export interface TronBlockData {
    /**
     * The block ID.
     */
    blockID: string

    /**
     * The block header.
     */
    block_header: TronBlockHeader
}

/**
 * Interface representing a TronWeb error response (type 1).
 */
interface TronWebError1 {
    /**
     * The error code.
     */
    code: string

    /**
     * The error message.
     */
    message: string

    /**
     * The transaction ID.
     */
    txid: string
}

/**
 * Interface representing a TronWeb error response (type 2).
 */
interface TronWebError2 {
    /**
     * The error message.
     */
    Error: string
}

/**
 * Type representing a TronWeb error response.
 */
type TronWebErrorResponse = TronWebError1 | TronWebError2

export {
    TronWeb,
    BlockTransaction,
    ContractExecutionParams,
    ChainParameter,
    Transaction,
    TronWebError1,
    TronWebError2,
    TronWebErrorResponse,
}

const logger = getLogger()

/**
 * Type representing provider settings.
 * It can be either a string representing the URL or an object containing the URL and an optional API key.
 */
export type ProviderSetting =
    | {
          /**
           * The URL of the provider.
           */
          url: string

          /**
           * The API key for the provider (optional).
           */
          apiKey?: string
      }
    | string

/**
 * Creates a TronWeb instance.
 *
 * @param {{ rpcSetting: ProviderSetting; privateKey: string } | TronWeb} signer - The signer object containing rpcSetting and privateKey, or an existing TronWeb instance.
 * @returns {TronWeb} The created TronWeb instance.
 */
export function createTronWeb(signer: { rpcSetting: ProviderSetting; privateKey: string } | TronWeb): TronWeb {
    if (!(signer instanceof TronWeb)) {
        const fullHostUrl = typeof signer.rpcSetting === 'string' ? signer.rpcSetting : signer.rpcSetting.url
        const client = new TronWeb({
            fullHost: StrategyFactory.get(fullHostUrl).asREST(fullHostUrl),
            headers: {
                'TRON-PRO-API-KEY': typeof signer.rpcSetting === 'string' ? '' : signer.rpcSetting.apiKey ?? '',
            },
            privateKey: signer.privateKey.replace(/^0x/, ''),
        })
        return client
    }
    return signer
}

/**
 * Signs and sends a Tron transaction.
 *
 * @param {object} txn - The transaction object containing data, to, and transaction overrides.
 * @param {object} signer - The signer object containing rpcSetting and privateKey, or an existing TronWeb instance.
 * @param {number} [permissionId] - The permission ID for multi-sig.
 * @returns {Promise<object>} A promise that resolves to an object containing txId, result, and wait function.
 */
export async function signAndSendTronTransaction(
    txn: {
        data: string
        to: string
    } & TransactionOverrides,
    signer: { rpcSetting: ProviderSetting; privateKey: string } | TronWeb,
    permissionId?: number // for multi-sig
): Promise<{ txId: string; result: TransactionResult; wait: () => Promise<TransactionInfo> }> {
    const signedTxn = await signTronTx(txn, signer, permissionId)
    const client = createTronWeb(signer)
    return sendTronTransaction(signedTxn, client)
}

/**
 * Sends a signed Tron transaction.
 *
 * @param {SignedTronTransaction} signedTxn - The signed Tron transaction.
 * @param {TronWeb} client - The TronWeb client.
 * @returns {Promise<object>} A promise that resolves to an object containing txId, result, and wait function.
 * @throws {Error} If the transaction broadcast fails.
 */
export async function sendTronTransaction(
    singedTxn: SignedTronTransaction,
    client: TronWeb
): Promise<{ txId: string; result: TransactionResult; wait: () => Promise<TransactionInfo> }> {
    // reference: https://developers.tron.network/reference/json-rpc-api-overview
    // JSON-RPC interface is not fully supported by the TRON network.
    // Furthermore, The JSON-RPC service needs to be enabled and set the port in the node configuration
    // file. If not configured, the service is disable by default.
    // broadcast signedTransaction
    const broadcastResponse = await client.trx.sendRawTransaction(singedTxn)
    if (broadcastResponse.code !== undefined) {
        const err = {
            error: broadcastResponse.code,
            message: TronWeb.toUtf8(broadcastResponse.message ?? ''),
        }
        throw new Error(JSON.stringify(err, null, 2))
    }

    return {
        txId: singedTxn.txID,
        result: broadcastResponse,
        wait: async (): Promise<TransactionInfo> => {
            return checkResult(client, singedTxn.txID)
        },
    }
}

/**
 * Signs a Tron transaction.
 *
 * @param {object} txn - The transaction object containing data, to, and transaction overrides.
 * @param {object} signer - The signer object containing rpcSetting and privateKey, or an existing TronWeb instance.
 * @param {number} [permissionId] - The permission ID for multi-sig.
 * @returns {Promise<SignedTronTransaction>} A promise that resolves to the signed Tron transaction.
 * @throws {Error} If the private key is invalid.
 */
export async function signTronTx(
    txn: {
        data: string
        to: string
    } & TransactionOverrides,
    _signer: { rpcSetting: ProviderSetting; privateKey: string } | TronWeb,
    permissionId?: number // for multi-sig
): Promise<SignedTronTransaction> {
    const signer: TronWeb = createTronWeb(_signer)

    // privateKey = privateKey.replace(/^0x/, '') // remove the 0x prefix
    // private key to address
    // const from = TronWeb.address.fromPrivateKey(privateKey)
    if (typeof signer.defaultAddress.hex !== 'string') {
        throw new Error(`signer.defaultAddress.hex is not a valid hex string`)
    }

    const partialTxn: PartialTronTransaction = {
        visible: false,
        txID: '',
        raw_data_hex: '',
        raw_data: {
            contract: [
                {
                    parameter: {
                        value: {
                            data: txn.data.replace(/^0x/, ''),
                            contract_address: TronWeb.address.toHex(txn.to),
                            owner_address: signer.defaultAddress.hex,
                        },
                        type_url: `type.googleapis.com/protocol.${TronTransactionType.TRIGGER_SMART_CONTRACT}`,
                    },
                    type: TronTransactionType.TRIGGER_SMART_CONTRACT,
                    Permission_id: permissionId,
                },
            ],
        },
    }

    const fullTxn = await fullFillTxn(signer, partialTxn, {
        gasLimit: txn.gasLimit,
        gasPrice: txn.gasPrice,
        energyFactor: txn.energyFactor,
        value: txn.value,
    })

    // sign transaction
    const signedTransaction = await signer.trx.sign(fullTxn)
    if (signedTransaction.signature === undefined) {
        throw new Error('Invalid private key provided')
    }
    return signedTransaction as SignedTronTransaction
}

let gasPriceCache: { time: number; value: string } = { time: 0, value: '' }
const energyFactorsCache = new Map<string, { time: number; value: number }>()

/**
 * Fills in the missing fields of a Tron transaction.
 *
 * @param {TronWeb} signer - The TronWeb client.
 * @param {PartialTronTransaction} txn - The partial Tron transaction.
 * @param {TransactionOverrides} [overrides={}] - The transaction overrides.
 * @returns {Promise<TronTransaction>} A promise that resolves to the full Tron transaction.
 */
export async function fullFillTxn(
    signer: TronWeb,
    txn: PartialTronTransaction,
    overrides: TransactionOverrides = {}
): Promise<TronTransaction> {
    const apiKey = signer.fullNode.headers['TRON-PRO-API-KEY']
    const etherProvider = new ethers.providers.StaticJsonRpcProvider({
        url: StrategyFactory.get(signer.fullNode.host).asJSONRPC(signer.fullNode.host),
        headers: {
            ...(typeof apiKey !== 'undefined' ? { 'TRON-PRO-API-KEY': apiKey } : {}),
        },
    })

    /**
     * Gets the current gas price.
     * cache the gasPrice with a 15sec TTL
     *
     * @returns {Promise<string>} A promise that resolves to the current gas price as a string.
     */
    async function getGasPrice(): Promise<string> {
        const { time, value } = gasPriceCache
        if (time > Time.NOW - 15 * Time.SECOND && value != '') return value
        const newGaspPrice = await etherProvider.getGasPrice().then((x) => x.toString())
        gasPriceCache = { time: Time.NOW, value: newGaspPrice }
        return newGaspPrice
    }

    /**
     * Estimates the gas limit for a given transaction.
     *
     * @param {PartialTronTransaction} raw - The partial Tron transaction.
     * @returns {Promise<number>} A promise that resolves to the estimated gas limit.
     */
    async function getGasLimit(raw: PartialTronTransaction): Promise<number> {
        const gasLimit = await etherProvider.estimateGas({
            to: raw.raw_data.contract[0].parameter.value.contract_address.replace(/^41/, '0x'), // need to slice off the "41" prefix that Tron appends to addresses
            data: '0x' + raw.raw_data.contract[0].parameter.value.data,
            from: raw.raw_data.contract[0].parameter.value.owner_address.replace(/^41/, '0x'),
            value: overrides.value ?? 0,
        })
        return gasLimit.toNumber()
    }

    /**
     * Gets the energy factor for a given transaction.
     * Caches the energy factor with a 10-minute TTL. Energy factors should be updated by Tron every 6 hours.
     *
     * @param {PartialTronTransaction} raw - The partial Tron transaction.
     * @returns {Promise<number>} A promise that resolves to the energy factor.
     */
    async function getEnergyFactor(raw: PartialTronTransaction): Promise<number> {
        /* eslint-disable @typescript-eslint/no-unsafe-assignment */
        const addr = raw.raw_data.contract[0].parameter.value.contract_address
        const cached = energyFactorsCache.get(addr)
        if (cached && cached.time > Time.NOW - 10 * Time.MINUTE) return cached.value
        const MAX_ENERGY_FACTOR = 1.2
        // refers: https://developers.tron.network/reference/getcontractinfo
        const response = await signer.fullNode.request(
            'wallet/getcontractinfo',
            { value: addr, visible: false },
            'post'
        )
        const contractInfo: ContractInfo = response as ContractInfo
        const energy_factor = contractInfo.contract_state.energy_factor ?? MAX_ENERGY_FACTOR
        energyFactorsCache.set(addr, { time: Time.NOW, value: energy_factor })
        return energy_factor
        /* eslint-enable @typescript-eslint/no-unsafe-assignment */
    }

    /**
     * Calculates the fee limit for a given transaction.
     *
     * @param {PartialTronTransaction} raw - The partial Tron transaction.
     * @param {TransactionOverrides} [overrides={}] - The transaction overrides.
     * @returns {Promise<number>} A promise that resolves to the calculated fee limit.
     */
    async function getFeeLimit(raw: PartialTronTransaction, overrides: TransactionOverrides = {}): Promise<number> {
        // https://developers.tron.network/docs/set-feelimit#how-to-determine-the-feelimit-parameter
        // https://developers.tron.network/reference/getcontractinfo, get energy_factor
        // https://developers.tron.network/docs/resource-model#dynamic-energy-model, max factor
        // Tight FeeLimit of contract transaction = estimated basic energy consumption * (1 + energy_factor) * EnergyPrice
        // Loose FeeLimit of contract transaction = estimated basic energy consumption * (1 + max_energy_factor) * EnergyPrice
        const MAX_FEE_LIMIT = 15000000000
        const energy_factor = overrides.energyFactor ?? (await getEnergyFactor(raw))
        const gasLimit = overrides.gasLimit ?? (await getGasLimit(raw))
        const energyPrice = overrides.gasPrice ?? Number(await getGasPrice())
        const factor = 1 + energy_factor
        const feeLimit = gasLimit * factor * energyPrice
        const feeLimit_adjusted = Math.ceil(feeLimit) * 1.2 // based on reading other parts of the code, we add a 20% cushion on fee limits
        return Math.floor(Math.min(feeLimit_adjusted, MAX_FEE_LIMIT))
    }

    const metadata = (await signer.fullNode.request('wallet/getblock', { detail: false }, 'post')) as TronBlockData
    const ref_block_bytes = metadata.block_header.raw_data.number.toString(16).slice(-4).padStart(4, '0')
    const ref_block_hash = metadata.blockID.slice(16, 32)
    const expiration = metadata.block_header.raw_data.timestamp + 60 * 1000
    const { timestamp } = metadata.block_header.raw_data

    const tx: TronTransaction = {
        ...txn,
        raw_data: {
            contract: [
                {
                    parameter: {
                        value: {
                            ...txn.raw_data.contract[0].parameter.value,
                            call_value: overrides.value ?? 0,
                        },
                        type_url: txn.raw_data.contract[0].parameter.type_url,
                    },
                    type: txn.raw_data.contract[0].type,
                },
            ],
            ref_block_bytes,
            ref_block_hash,
            expiration,
            fee_limit: await getFeeLimit(txn, overrides),
            timestamp,
        },
    }
    const pb = signer.utils.transaction.txJsonToPb(tx)
    tx.txID = signer.utils.transaction.txPbToTxID(pb).replace(/^0x/, '')
    tx.raw_data_hex = signer.utils.transaction.txPbToRawDataHex(pb).toLowerCase()

    return tx
}

/**
 * Checks the result of a Tron transaction.
 *
 * @param {TronWeb} tronWeb - The TronWeb client.
 * @param {string} txId - The transaction ID.
 * @returns {Promise<TransactionInfo>} A promise that resolves to the transaction info.
 * @throws {Error} If the transaction fails or times out.
 */
export async function checkResult(tronWeb: TronWeb, txId: string): Promise<TransactionInfo> {
    const startTime = Date.now()
    const waitTimeout = 1000 * 60 * 5 // 5 minutes
    // TODO: get the block producer interval from the chain and sleep for that time
    const wait = async function (txId: string): Promise<TransactionInfo> {
        let tries = 0
        while (tries++ < 20) {
            const output = await tronWeb.trx.getTransactionInfo(txId)
            if (Object.keys(output).length > 0) {
                return output
            }

            // check if timeout
            if (Date.now() - startTime > waitTimeout) {
                throw new Error('Timeout waiting for transaction to be processed')
            }
            // wait 1 seconds for next check, mainnet block producer interval is 3 seconds,
            // but we need a small interval for the local network to speed up the test
            await sleep(1200)
        }
        throw new Error(`Failed to get transactionInfo for txId: ${txId}`)
    }

    const output = await wait(txId)

    if (output.result !== undefined && output.result === 'FAILED') {
        throw new Error(TronWeb.toUtf8(output.resMessage ?? ''))
    }

    if (!Object.prototype.hasOwnProperty.call(output, 'contractResult')) {
        throw new Error('Failed to execute: ' + JSON.stringify(output, null, 2))
    }

    return output
}
