// Base unit in milliseconds
const MILLISECOND = 1
const SECOND = 1000 * MILLISECOND
const MINUTE = 60 * SECOND
const HOUR = 60 * MINUTE
const DAY = 24 * HOUR

/**
 * Object representing various time units and the current time.
 */
export const Time = {
    /**
     * Millisecond unit.
     */
    MILLISECOND,

    /**
     * Second unit.
     */
    SECOND,

    /**
     * Minute unit.
     */
    MINUTE,

    /**
     * Hour unit.
     */
    HOUR,

    /**
     * Day unit.
     */
    DAY,

    /**
     * Gets the current time in milliseconds since the Unix epoch.
     * @returns {number} The current time in milliseconds.
     */
    get NOW() {
        return Date.now()
    },
} as const
